SELECT cr.*, pr.*, CDate(Left([cr].[requestDate],10)) AS RequestDateReal, ddReq.[requestType] AS RequestTypeName, c.[customerName] AS CustomerName, req.[firstName] & " " & req.[lastName] AS RequestorName, plan.[firstName] & " " & plan.[lastName] AS PlannerName, u.[unitName] AS UnitName, ddProd.[productionType] AS ProductionTypeName, ddVolType.[volumeType] AS VolumeTypeName, ddVolTime.[volumeTiming] AS VolumeTimingName, ddRes.[results] AS CapacityResultsName, ddQuote.[quoteAward] AS QuoteStatusName
FROM ((((((((((tblCapacityRequests AS cr LEFT JOIN tblCapacityRequest_partnumbers AS pr ON cr.[RecordID] = pr.[requestId]) LEFT JOIN tblDropDowns_StrategicPlanning AS ddReq ON cr.[requestType] = ddReq.[recordId]) LEFT JOIN tblCustomers AS c ON cr.[Customer] = c.[ID]) LEFT JOIN tblPermissions AS req ON cr.[Requestor] = req.[ID]) LEFT JOIN tblPermissions AS plan ON pr.[planner] = plan.[ID]) LEFT JOIN tblUnits AS u ON pr.[unitId] = u.[recordID]) LEFT JOIN tblDropDowns_StrategicPlanning AS ddProd ON pr.[productionType] = ddProd.[recordId]) LEFT JOIN tblDropDowns_StrategicPlanning AS ddVolType ON pr.[volumeType] = ddVolType.[recordId]) LEFT JOIN tblDropDowns_StrategicPlanning AS ddVolTime ON pr.[volumeTiming] = ddVolTime.[recordId]) LEFT JOIN tblDropDowns_StrategicPlanning AS ddRes ON pr.[capacityResults] = ddRes.[recordId]) LEFT JOIN tblDropDowns_StrategicPlanning AS ddQuote ON pr.[quoteStatus] = ddQuote.[recordId];

